            CDEXToken.transfer(msg.sender, reward.add(loyaltyBonus));

            emit RewardPaid(msg.sender, reward);

            if(loyaltyBonus > 0) {
                emit LoyaltyBonusPaid(msg.sender, loyaltyBonus);
            }
        }
    }


