        ERC20Mintable _biffysLove,
        uint _duration,
        uint _initreward,
        uint _starttime,
        address _owner
    ) public initializer {
        Ownable.initialize(_owner);
        LPTokenWrapper.init(_loveLP);
        biffysLove = _biffysLove;
        duration = _duration;
        initreward = _initreward;
        starttime = _starttime;
    }

    modifier updateReward(address account) {
        rewardPerTokenStored = rewardPerToken();
        lastUpdateTime = lastTimeRewardApplicable();
        if (account != address(0)) {
            rewards[account] = earned(account);
            userRewardPerTokenPaid[account] = rewardPerTokenStored;
        }
        _;
    }

    function lastTimeRewardApplicable() public view returns (uint256) {
        return Math.min(block.timestamp, periodFinish);
    }

    function rewardPerToken() public view returns (uint256) {
        if (totalSupply() == 0) {
            return rewardPerTokenStored;
        }
        return
            rewardPerTokenStored.add(
                lastTimeRewardApplicable()
                    .sub(lastUpdateTime)
                    .mul(rewardRate)
                    .mul(1e18)
                    .div(totalSupply())
            );
    }

    function earned(address account) public view returns (uint256) {
        return
            balanceOf(account)
                .mul(rewardPerToken().sub(userRewardPerTokenPaid[account]))
                .div(1e18)
                .add(rewards[account]);
    }


    function stake(uint256 amount) public updateReward(msg.sender) checkhalve checkStart {
        require(amount > 0, "Cannot stake 0");
        super.stake(amount);

        if (userRewardPerTokenPaid[msg.sender] == 0) {
            userRewardPerTokenPaid[msg.sender] = rewardPerToken();
        }
        emit Staked(msg.sender, amount);
    }

    function getReward() public updateReward(msg.sender) checkhalve checkStart {
        uint256 reward = earned(msg.sender);
        if (reward > 0) {
            rewards[msg.sender] = 0;
            biffysLove.transfer(msg.sender, reward);
            emit RewardPaid(msg.sender, reward);
        }
    }


    function setInitReward(uint amtLoveWeiPerPeriod) external onlyOwner {
        require(rewardRate == 0, "Must not have yet set the reward rate.");
        initreward = amtLoveWeiPerPeriod;
    }


    function fixRewardPerTokenStored(address account, uint _rewardPerToken) external onlyOwner {
        require(earned(account) > 0, "Must be a staker");
        require(userRewardPerTokenPaid[account] == 0, "Must have incorrect reward");
        userRewardPerTokenPaid[account] = _rewardPerToken;
    }


    function fixEmissionRate(uint _initReward) external onlyOwner {
        initreward = _initReward;
        biffysLove.mint(address(this), initreward.sub(biffysLove.balanceOf(address(this))));
        rewardRate = initreward.div(periodFinish.sub(now));
    }

    modifier checkhalve() {
        if (block.timestamp >= periodFinish) {
            initreward = initreward.mul(50).div(100);
            biffysLove.mint(address(this), initreward);

            rewardRate = initreward.div(duration);
            periodFinish = block.timestamp.add(duration);
            emit RewardAdded(initreward);
        }
        _;
    }

    modifier checkStart(){
        require(block.timestamp > starttime, "not start");
        _;
    }
}

pragma solidity 0.8.4;

contract Owned {
    modifier onlyOwner() {
        require(msg.sender == owner);
        _;
    }
    address public owner;

    function changeOwnership(address payable _newOwner) public onlyOwner {
        owner = _newOwner;
    }

}

interface BEP {

    function totalSupply() external view returns (uint256);
    function balanceOf(address account) external view returns (uint256);
    function transfer(address recipient, uint256 amount) external returns (bool);
    function allowance(address owner, address spender) external view returns (uint256);
    function approve(address spender, uint256 amount) external returns (bool);
    function transferFrom(address sender, address recipient, uint256 amount) external returns (bool);
    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
}

contract BEP20 {
    string public symbol;
    string public name;
    uint8 public decimals;
    uint256 public totalSupply;
    mapping (address=>uint256) balances;
    mapping (address=>mapping (address=>uint256)) allowed;
    event Transfer(address indexed _from, address indexed _to, uint256 _value);
    event Approval(address indexed _owner, address indexed _spender, uint256 _value);

    function balanceOf(address _owner) view public returns (uint256 balance) {return balances[_owner];}

    function transfer(address _to, uint256 _amount) public returns (bool success) {
        require (balances[msg.sender]>=_amount&&_amount>0&&balances[_to]+_amount>balances[_to]);
        balances[msg.sender]-=_amount;
        balances[_to]+=_amount;
        emit Transfer(msg.sender,_to,_amount);
        return true;
    }

    function transferFrom(address _from,address _to,uint256 _amount) public returns (bool success) {
        require (balances[_from]>=_amount&&allowed[_from][msg.sender]>=_amount&&_amount>0&&balances[_to]+_amount>balances[_to]);
        balances[_from]-=_amount;
        allowed[_from][msg.sender]-=_amount;
        balances[_to]+=_amount;
        emit Transfer(_from, _to, _amount);
        return true;
    }

    function approve(address _spender, uint256 _amount) public returns (bool success) {
        allowed[msg.sender][_spender]=_amount;
        emit Approval(msg.sender, _spender, _amount);
        return true;
    }

    function allowance(address _owner, address _spender) view public returns (uint256 remaining) {
      return allowed[_owner][_spender];
    }

    function _mint(address account, uint256 amount) internal virtual {
        require(account != address(0), "BEP20: mint to the zero address");

        _beforeTokenTransfer(address(0), account, amount);

        totalSupply += amount;
        balances[account] += amount;
        emit Transfer(address(0), account, amount);
    }


     function _burn(address account, uint256 amount) internal virtual {
        require(account != address(0), "BEP20: burn from the zero address");

        _beforeTokenTransfer(account, address(0), amount);

        uint256 accountBalance = balances[account];
        require(accountBalance >= amount, "BEP20: burn amount exceeds balance");
        balances[account] = accountBalance - amount;
        totalSupply -= amount;

        emit Transfer(account, address(0), amount);
    }
    function _beforeTokenTransfer(address from, address to, uint256 amount) internal virtual { }
}

contract TimeLock is Owned, BEP20 {

    struct LockedAccounts {
        address account;
        uint amount;
        uint time;
        Locked[] locked;
    }

    struct Locked {
        uint time;
        uint amount;
        uint lockedAt;
    }

    mapping(address => LockedAccounts) lock;

    function timelock(address _lockAccount, uint time, uint amount) public onlyOwner returns (bool) {
        require(amount > 0, "TimeLock: Amount cannot be zero");
        transfer(address(this), amount);
        lock[_lockAccount].account = _lockAccount;
        lock[_lockAccount].amount = amount;
        lock[_lockAccount].time = time;
        lock[_lockAccount].locked.push(Locked(time, amount, block.timestamp));
        return true;
    }

    function release() public returns (bool) {
        LockedAccounts storage lockedAccount = lock[msg.sender];

        for(uint i = 0; i < lockedAccount.locked.length; i++) {
            Locked storage loc = lockedAccount.locked[i];
            require(block.timestamp >= (loc.time + loc.lockedAt), "TimeLock: Release time not reached");
            uint amount = loc.amount;
            BEP(address(this)).transfer(msg.sender, amount);
            loc.amount = 0;
            loc.time = 0;
            loc.lockedAt = 0;
        }
        return true;
    }

    function lockedAccountDetails(address user) public view returns (uint[] memory, uint[] memory, uint[] memory, uint[] memory, uint) {
        uint lockedLength = lock[user].locked.length;
        uint[] memory lockedAmounts = new uint[](lockedLength);
        uint[] memory lockTimes = new uint[](lockedLength);
        uint[] memory lockedAt = new uint[](lockedLength);
        uint[] memory totalLockTime = new uint[](lockedLength);
        uint currentTime = block.timestamp;


        for(uint i = 0; i < lockedLength; i++) {
            lockedAmounts[i] = lock[user].locked[i].amount;
            lockTimes[i] = lock[user].locked[i].time;
            lockedAt[i] = lock[user].locked[i].lockedAt;
            totalLockTime[i] = lock[user].locked[i].time + lock[user].locked[i].lockedAt;
        }
        return(lockedAmounts, lockTimes, lockedAt, totalLockTime, currentTime);
    }
}

contract Citrus  is TimeLock {

    constructor() {
        symbol = "CTS";
        name = "Citrus";
        decimals = 18;                                    
        totalSupply = 383000000 * 10**18;           

        owner = msg.sender;
        balances[owner] = totalSupply;
    }

    function mint(address to, uint amount) external {
        require(msg.sender == owner, 'only admin');
        _mint(to, amount);
    }

    function burn(address from, uint amount) external {
        require(msg.sender == owner, 'only admin');
        _burn(from, amount);
    }

}

pragma solidity ^0.8.0;

import "./IERC20.sol";
import "./extensions/IERC20Metadata.sol";
import "../../utils/Context.sol";


contract ERC20 is Context, IERC20, IERC20Metadata {
    mapping (address => uint256) private _balances;

    mapping (address => mapping (address => uint256)) private _allowances;

    uint256 private _totalSupply;

    string private _name;
    string private _symbol;


    constructor (string memory name_, string memory symbol_) {
        _name = name_;
        _symbol = symbol_;
    }


    function name() public view virtual override returns (string memory) {
        return _name;
    }


    function symbol() public view virtual override returns (string memory) {
        return _symbol;
    }


    function decimals() public view virtual override returns (uint8) {
        return 18;
    }


    function totalSupply() public view virtual override returns (uint256) {
        return _totalSupply;
    }


    function balanceOf(address account) public view virtual override returns (uint256) {
        return _balances[account];
    }


    function transfer(address recipient, uint256 amount) public virtual override returns (bool) {
        _transfer(_msgSender(), recipient, amount);
        return true;
    }


    function allowance(address owner, address spender) public view virtual override returns (uint256) {
        return _allowances[owner][spender];
    }


    function approve(address spender, uint256 amount) public virtual override returns (bool) {
        _approve(_msgSender(), spender, amount);
        return true;
    }


    function transferFrom(address sender, address recipient, uint256 amount) public virtual override returns (bool) {
        _transfer(sender, recipient, amount);

        uint256 currentAllowance = _allowances[sender][_msgSender()];
        require(currentAllowance >= amount, "ERC20: transfer amount exceeds allowance");
        _approve(sender, _msgSender(), currentAllowance - amount);

        return true;
    }


    function increaseAllowance(address spender, uint256 addedValue) public virtual returns (bool) {
        _approve(_msgSender(), spender, _allowances[_msgSender()][spender] + addedValue);
        return true;
    }


    function decreaseAllowance(address spender, uint256 subtractedValue) public virtual returns (bool) {
        uint256 currentAllowance = _allowances[_msgSender()][spender];
        require(currentAllowance >= subtractedValue, "ERC20: decreased allowance below zero");
        _approve(_msgSender(), spender, currentAllowance - subtractedValue);

        return true;
    }


    function _transfer(address sender, address recipient, uint256 amount) internal virtual {
        require(sender != address(0), "ERC20: transfer from the zero address");
        require(recipient != address(0), "ERC20: transfer to the zero address");

        _beforeTokenTransfer(sender, recipient, amount);

        uint256 senderBalance = _balances[sender];
        require(senderBalance >= amount, "ERC20: transfer amount exceeds balance");
        _balances[sender] = senderBalance - amount;
        _balances[recipient] += amount;

        emit Transfer(sender, recipient, amount);
    }


    function _mint(address account, uint256 amount) internal virtual {
        require(account != address(0), "ERC20: mint to the zero address");

        _beforeTokenTransfer(address(0), account, amount);

        _totalSupply += amount;
        _balances[account] += amount;
        emit Transfer(address(0), account, amount);
    }


    function _burn(address account, uint256 amount) internal virtual {
        require(account != address(0), "ERC20: burn from the zero address");

        _beforeTokenTransfer(account, address(0), amount);

        uint256 accountBalance = _balances[account];
        require(accountBalance >= amount, "ERC20: burn amount exceeds balance");
        _balances[account] = accountBalance - amount;
        _totalSupply -= amount;

        emit Transfer(account, address(0), amount);
    }


    function _approve(address owner, address spender, uint256 amount) internal virtual {
        require(owner != address(0), "ERC20: approve from the zero address");
        require(spender != address(0), "ERC20: approve to the zero address");

        _allowances[owner][spender] = amount;
        emit Approval(owner, spender, amount);
    }


    function _beforeTokenTransfer(address from, address to, uint256 amount) internal virtual { }
}

