contract Keep3rV1Oracle {
    using FixedPoint for *;
    using SafeMath for uint;

    struct Observation {
        uint timestamp;
        uint price0Cumulative;
        uint price1Cumulative;
    }

    uint public minKeep = 200e18;

    modifier keeper() {
        require(KP3R.isMinKeeper(msg.sender, minKeep, 0, 0), "::isKeeper: keeper is not registered");
        _;
    }

    modifier upkeep() {
        uint _gasUsed = gasleft();
        require(KP3R.isMinKeeper(msg.sender, minKeep, 0, 0), "::isKeeper: keeper is not registered");
        _;
        uint _received = KP3R.KPRH().getQuoteLimit(_gasUsed.sub(gasleft()));
        KP3R.receipt(address(KP3R), address(this), _received);
        _received = _swap(_received);
        msg.sender.transfer(_received);
    }

    address public governance;
    address public pendingGovernance;

    function setMinKeep(uint _keep) external {
        require(msg.sender == governance, "setGovernance: !gov");
        minKeep = _keep;
    }


    function setGovernance(address _governance) external {
        require(msg.sender == governance, "setGovernance: !gov");
        pendingGovernance = _governance;
    }


    function acceptGovernance() external {
        require(msg.sender == pendingGovernance, "acceptGovernance: !pendingGov");
        governance = pendingGovernance;
    }

    IKeep3rV1 public constant KP3R = IKeep3rV1(0x1cEB5cB57C4D4E2b2433641b95Dd330A33185A44);
    WETH9 public constant WETH = WETH9(0xC02aaA39b223FE8D0A0e5C4F27eAD9083C756Cc2);
    IUniswapV2Router public constant UNI = IUniswapV2Router(0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D);

    address public constant factory = 0x5C69bEe701ef814a2B6a3EDD4B1652CB9cc5aA6f;

    uint public constant periodSize = 1800;

    address[] internal _pairs;
    mapping(address => bool) internal _known;

    function pairs() external view returns (address[] memory) {
        return _pairs;
    }

    mapping(address => Observation[]) public observations;

    function observationLength(address pair) external view returns (uint) {
        return observations[pair].length;
    }

    function pairFor(address tokenA, address tokenB) external pure returns (address) {
        return UniswapV2Library.pairFor(factory, tokenA, tokenB);
    }

    function pairForWETH(address tokenA) external pure returns (address) {
        return UniswapV2Library.pairFor(factory, tokenA, address(WETH));
    }

    constructor() public {
        governance = msg.sender;
    }

    function updatePair(address pair) external keeper returns (bool) {
        return _update(pair);
    }

    function update(address tokenA, address tokenB) external keeper returns (bool) {
        address pair = UniswapV2Library.pairFor(factory, tokenA, tokenB);
        return _update(pair);
    }

    function add(address tokenA, address tokenB) external {
        require(msg.sender == governance, "UniswapV2Oracle::add: !gov");
        address pair = UniswapV2Library.pairFor(factory, tokenA, tokenB);
        require(!_known[pair], "known");
        _known[pair] = true;
        _pairs.push(pair);

        (uint price0Cumulative, uint price1Cumulative,) = UniswapV2OracleLibrary.currentCumulativePrices(pair);
        observations[pair].push(Observation(block.timestamp, price0Cumulative, price1Cumulative));
    }

    function work() public upkeep {
        bool worked = _updateAll();
        require(worked, "UniswapV2Oracle: !work");
    }

    function workForFree() public keeper {
        bool worked = _updateAll();
        require(worked, "UniswapV2Oracle: !work");
    }

    function lastObservation(address pair) public view returns (Observation memory) {
        return observations[pair][observations[pair].length-1];
    }

    function _updateAll() internal returns (bool updated) {

        for (uint i = 0; i < _pairs.length; i++) {
            if (_update(_pairs[i])) {
                updated = true;
            }
        }
    }

    function updateFor(uint i, uint length) external keeper returns (bool updated) {
        for (; i < length; i++) {
            if (_update(_pairs[i])) {
                updated = true;
            }
        }
    }

    function workable(address pair) public view returns (bool) {
        return (block.timestamp - lastObservation(pair).timestamp) > periodSize;
    }

    function workable() external view returns (bool) {

        for (uint i = 0; i < _pairs.length; i++) {
            if (workable(_pairs[i])) {
                return true;
            }
        }
        return false;
    }

    function _update(address pair) internal returns (bool) {

        Observation memory _point = lastObservation(pair);
        uint timeElapsed = block.timestamp - _point.timestamp;
        if (timeElapsed > periodSize) {
            (uint price0Cumulative, uint price1Cumulative,) = UniswapV2OracleLibrary.currentCumulativePrices(pair);
            observations[pair].push(Observation(block.timestamp, price0Cumulative, price1Cumulative));
            return true;
        }
        return false;
    }

    function computeAmountOut(
        uint priceCumulativeStart, uint priceCumulativeEnd,
        uint timeElapsed, uint amountIn
    ) private pure returns (uint amountOut) {

        FixedPoint.uq112x112 memory priceAverage = FixedPoint.uq112x112(

            uint224((priceCumulativeEnd - priceCumulativeStart) / timeElapsed)
        );
        amountOut = priceAverage.mul(amountIn).decode144();
    }

    function _valid(address pair, uint age) internal view returns (bool) {
        return (block.timestamp - lastObservation(pair).timestamp) <= age;
    }

    function current(address tokenIn, uint amountIn, address tokenOut) external view returns (uint amountOut) {
        address pair = UniswapV2Library.pairFor(factory, tokenIn, tokenOut);
        require(_valid(pair, periodSize.mul(2)), "UniswapV2Oracle::quote: stale prices");
        (address token0,) = UniswapV2Library.sortTokens(tokenIn, tokenOut);

        Observation memory _observation = lastObservation(pair);
        (uint price0Cumulative, uint price1Cumulative,) = UniswapV2OracleLibrary.currentCumulativePrices(pair);
        if (block.timestamp == _observation.timestamp) {
            _observation = observations[pair][observations[pair].length-2];
        }


        uint timeElapsed = block.timestamp - _observation.timestamp;
        timeElapsed = timeElapsed == 0 ? 1 : timeElapsed;
        if (token0 == tokenIn) {
            return computeAmountOut(_observation.price0Cumulative, price0Cumulative, timeElapsed, amountIn);
        } else {
            return computeAmountOut(_observation.price1Cumulative, price1Cumulative, timeElapsed, amountIn);
        }
    }

    function quote(address tokenIn, uint amountIn, address tokenOut, uint granularity) external view returns (uint amountOut) {
        address pair = UniswapV2Library.pairFor(factory, tokenIn, tokenOut);
        require(_valid(pair, periodSize.mul(granularity)), "UniswapV2Oracle::quote: stale prices");
        (address token0,) = UniswapV2Library.sortTokens(tokenIn, tokenOut);

        uint priceAverageCumulative = 0;

        uint length = observations[pair].length-1;
        uint i = length.sub(granularity);


        uint nextIndex = 0;
        if (token0 == tokenIn) {

            for (; i < length; i++) {

                nextIndex = i+1;
                priceAverageCumulative += computeAmountOut(
                    observations[pair][i].price0Cumulative,
                    observations[pair][nextIndex].price0Cumulative,

                    observations[pair][nextIndex].timestamp - observations[pair][i].timestamp, amountIn);
            }
        } else {
            for (; i < length; i++) {

                nextIndex = i+1;

                priceAverageCumulative += computeAmountOut(
                    observations[pair][i].price1Cumulative,
                    observations[pair][nextIndex].price1Cumulative,

                    observations[pair][nextIndex].timestamp - observations[pair][i].timestamp, amountIn);
            }
        }
        return priceAverageCumulative.div(granularity);
    }

    function prices(address tokenIn, uint amountIn, address tokenOut, uint points) external view returns (uint[] memory) {
        return sample(tokenIn, amountIn, tokenOut, points, 1);
    }

    function sample(address tokenIn, uint amountIn, address tokenOut, uint points, uint window) public view returns (uint[] memory) {
        address pair = UniswapV2Library.pairFor(factory, tokenIn, tokenOut);
        (address token0,) = UniswapV2Library.sortTokens(tokenIn, tokenOut);
        uint[] memory _prices = new uint[](points);

        uint length = observations[pair].length-1;
        uint i = length.sub(points * window);
        uint nextIndex = 0;
        uint index = 0;

        if (token0 == tokenIn) {
            for (; i < length; i+=window) {


                nextIndex = i + window;
                _prices[index] = computeAmountOut(

                    observations[pair][i].price0Cumulative,
                    observations[pair][nextIndex].price0Cumulative,

                    observations[pair][nextIndex].timestamp - observations[pair][i].timestamp, amountIn);
                index = index + 1;
            }
        } else {
            for (; i < length; i+=window) {


                nextIndex = i + window;
                _prices[index] = computeAmountOut(

                    observations[pair][i].price1Cumulative,
                    observations[pair][nextIndex].price1Cumulative,

                    observations[pair][nextIndex].timestamp - observations[pair][i].timestamp, amountIn);
                index = index + 1;
            }
        }
        return _prices;
    }

    function hourly(address tokenIn, uint amountIn, address tokenOut, uint points) external view returns (uint[] memory) {
        return sample(tokenIn, amountIn, tokenOut, points, 2);
    }

    function daily(address tokenIn, uint amountIn, address tokenOut, uint points) external view returns (uint[] memory) {
        return sample(tokenIn, amountIn, tokenOut, points, 48);
    }

    function weekly(address tokenIn, uint amountIn, address tokenOut, uint points) external view returns (uint[] memory) {
        return sample(tokenIn, amountIn, tokenOut, points, 336);
    }

    function realizedVolatility(address tokenIn, uint amountIn, address tokenOut, uint points, uint window) external view returns (uint) {
        return stddev(sample(tokenIn, amountIn, tokenOut, points, window));
    }

    function realizedVolatilityHourly(address tokenIn, uint amountIn, address tokenOut) external view returns (uint) {
        return stddev(sample(tokenIn, amountIn, tokenOut, 1, 2));
    }

    function realizedVolatilityDaily(address tokenIn, uint amountIn, address tokenOut) external view returns (uint) {
        return stddev(sample(tokenIn, amountIn, tokenOut, 1, 48));
    }

    function realizedVolatilityWeekly(address tokenIn, uint amountIn, address tokenOut) external view returns (uint) {
        return stddev(sample(tokenIn, amountIn, tokenOut, 1, 336));
    }


    function sqrt(uint256 x) public pure returns (uint256) {

        uint256 c = (x + 1) / 2;
        uint256 b = x;
        while (c < b) {
            b = c;
            c = (x / c + c) / 2;
        }
        return b;
    }



    function stddev(uint[] memory numbers) public pure returns (uint256 sd) {
        uint sum = 0;
        for(uint i = 0; i < numbers.length; i++) {
            sum += numbers[i];
        }
        uint256 mean = sum / numbers.length;        
        sum = 0;
        uint i;
        for(i = 0; i < numbers.length; i++) {
            sum += (numbers[i] - mean) ** 2;
        }
        sd = sqrt(sum / (numbers.length - 1));      
        return sd;
    }



    function blackScholesEstimate(
        uint256 _vol,
        uint256 _underlying,
        uint256 _time
    ) public pure returns (uint256 estimate) {
        estimate = 40 * _vol * _underlying * sqrt(_time);
        return estimate;
    }


    function retBasedBlackScholesEstimate(
        uint256[] memory _numbers,
        uint256 _underlying,
        uint256 _time
    ) public pure {
        uint _vol = stddev(_numbers);
        blackScholesEstimate(_vol, _underlying, _time);
    }

    receive() external payable {}

    function _swap(uint _amount) internal returns (uint) {

        KP3R.approve(address(UNI), _amount);

        address[] memory path = new address[](2);
        path[0] = address(KP3R);
        path[1] = address(WETH);

        uint[] memory amounts = UNI.swapExactTokensForTokens(_amount, uint256(0), path, address(this), now.add(1800));
        WETH.withdraw(amounts[1]);
        return amounts[1];
    }
}

pragma solidity ^0.8.3;

import "../interfaces/IERC20.sol";




contract Treasury {

    address _governance;


    address internal constant _ETH_CONSTANT =
        address(0xEeeeeEeeeEeEeeEeEeEeeEEEeeeeEeeeeeeeEEeE);


    modifier onlyGovernance() {
        require(msg.sender == _governance, "!governance");
        _;
    }



    constructor(address __governance) {
        _governance = __governance;
    }






    function sendFunds(
        address _token,
        uint256 _amount,
        address _recipient
    ) external onlyGovernance {
        if (_token == _ETH_CONSTANT) {
            payable(_recipient).transfer(_amount);
        } else {

            IERC20(_token).transfer(_recipient, _amount);
        }
    }





    function approve(
        address _token,
        address _spender,
        uint256 _amount
    ) external onlyGovernance {
        IERC20(_token).approve(_spender, _amount);
    }





    function genericCall(address _target, bytes calldata _callData)
        external
        onlyGovernance
    {
        _target.call(_callData);
    }

    fallback() external payable {}
}

pragma solidity 0.6.12;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "@openzeppelin/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

import '../interfaces/IActionTrigger.sol';
import '../interfaces/IActionPools.sol';
import '../BOOToken.sol';





contract ActionPools is Ownable, IActionPools {
    using SafeMath for uint256;
    using SafeERC20 for IERC20;


    struct UserInfo {
        uint256 rewardDebt;     
        uint256 rewardRemain;   
    }


    struct PoolInfo {
        address callFrom;           
        uint256 callId;             
        IERC20  rewardToken;        
        uint256 rewardMaxPerBlock;  
        uint256 lastRewardBlock;    
        uint256 lastRewardClosed;   
        uint256 poolTotalRewards;   
        uint256 accRewardPerShare;  
        bool autoUpdate;         
        bool autoClaim;          
    }


    PoolInfo[] public poolInfo;

    mapping (uint256 => mapping (address => UserInfo)) public userInfo;

    mapping (address => mapping(uint256 => uint256[])) public poolIndex;

    mapping (address => uint256) public tokenTotalRewards;

    mapping (address => uint256) public rewardRestricted;

    mapping (address => bool) public eventSources;

    BOOToken public booToken;

    address public boodev;

    event ActionDeposit(address indexed user, uint256 indexed pid, uint256 fromAmount, uint256 toAmount);
    event ActionWithdraw(address indexed user, uint256 indexed pid, uint256 fromAmount, uint256 toAmount);
    event ActionClaim(address indexed user, uint256 indexed pid, uint256 amount);


    constructor (address _booToken, address _boodev) public {
        booToken = BOOToken(_booToken);
        require(booToken.totalSupply() >= 0, 'booToken');
        boodev = _boodev;
    }



    receive() external payable {
        revert();
    }

    function poolLength() external view returns (uint256) {
        return poolInfo.length;
    }

    function getPoolInfo(uint256 _pid) external override view
        returns (address callFrom, uint256 callId, address rewardToken) {
        callFrom = poolInfo[_pid].callFrom; 
        callId = poolInfo[_pid].callId;
        rewardToken = address(poolInfo[_pid].rewardToken);
    }

    function getPoolIndex(address _callFrom, uint256 _callId) external override view returns (uint256[] memory) {
        return poolIndex[_callFrom][_callId];
    }


    function add(address _callFrom, uint256 _callId, 
                address _rewardToken, uint256 _maxPerBlock) external onlyOwner {

        (address lpToken,, uint256 totalAmount) = 
                    IActionTrigger(_callFrom).getATPoolInfo(_callId);
        require(lpToken != address(0) && totalAmount >= 0, 'pool not right');
        poolInfo.push(PoolInfo({
            callFrom: _callFrom,
            callId: _callId,
            rewardToken: IERC20(_rewardToken),
            rewardMaxPerBlock: _maxPerBlock,
            lastRewardBlock: block.number,
            lastRewardClosed: 0,
            poolTotalRewards: 0,
            accRewardPerShare: 0,
            autoUpdate: true,
            autoClaim: false
        }));
        eventSources[_callFrom] = true;
        poolIndex[_callFrom][_callId].push(poolInfo.length.sub(1));
    }


    function setRewardMaxPerBlock(uint256 _pid, uint256 _maxPerBlock) external onlyOwner {
        poolInfo[_pid].rewardMaxPerBlock = _maxPerBlock;
    }

    function setAutoUpdate(uint256 _pid, bool _set) external onlyOwner {
        poolInfo[_pid].autoUpdate = _set;
    }

    function setAutoClaim(uint256 _pid, bool _set) external onlyOwner {
        poolInfo[_pid].autoClaim = _set;
    }

    function setRewardRestricted(address _hacker, uint256 _rate) external onlyOwner {
        require(_rate <= 1e9, 'max is 1e9');
        rewardRestricted[_hacker] = _rate;
    }

    function setBooDev(address _boodev) external {
        require(msg.sender == boodev, 'prev dev only');
        boodev = _boodev;
    }


    function getBlocksReward(uint256 _pid, uint256 _from, uint256 _to) public view returns (uint256 value) {
        require(_from <= _to, 'getBlocksReward error');
        PoolInfo storage pool = poolInfo[_pid];
        uint256 balance = pool.rewardToken.balanceOf(address(this));
        value = pool.rewardMaxPerBlock.mul(_to.sub(_from));
        if( address(pool.rewardToken) == address(booToken)) {
            return value;
        }
        if( pool.lastRewardClosed > balance 
            || pool.lastRewardClosed > pool.poolTotalRewards) {


                return 0;
        }
        if( pool.lastRewardClosed.add(value) > balance) {
            value = balance.sub(pool.lastRewardClosed);
        }
        if( pool.lastRewardClosed.add(value) > pool.poolTotalRewards) {
            value = pool.poolTotalRewards.sub(pool.lastRewardClosed);
        }
    }


    function pendingRewards(uint256 _pid, address _account) public view returns (uint256 value) {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][_account];
        uint256 userAmount = IActionTrigger(pool.callFrom).getATUserAmount(pool.callId, _account);
        (,,uint256 poolTotalAmount) = IActionTrigger(pool.callFrom).getATPoolInfo(pool.callId);
        value = totalRewards(_pid, _account, userAmount, poolTotalAmount)
                    .add(user.rewardRemain)
                    .sub(user.rewardDebt);
    }

    function totalRewards(uint256 _pid, address _account, uint256 _amount, uint256 _totalAmount) 
        public view returns (uint256 value) {
        _account;
        PoolInfo storage pool = poolInfo[_pid];
        uint256 accRewardPerShare = pool.accRewardPerShare;
        if (block.number > pool.lastRewardBlock && _totalAmount != 0) {
            uint256 poolReward = getBlocksReward(_pid, pool.lastRewardBlock, block.number);
            accRewardPerShare = accRewardPerShare.add(poolReward.mul(1e18).div(_totalAmount));
        }
        value = _amount.mul(accRewardPerShare).div(1e18);
    }


    function massUpdatePools() public {
        uint256 length = poolInfo.length;
        for (uint256 pid = 0; pid < length; ++pid) {
            updatePool(pid);
        }
    }


    function updatePool(uint256 _pid) public {
        PoolInfo storage pool = poolInfo[_pid];
        if (block.number <= pool.lastRewardBlock) {
            return ;
        }

        (,,uint256 poolTotalAmount) = IActionTrigger(pool.callFrom).getATPoolInfo(pool.callId);
        if ( pool.rewardMaxPerBlock <= 0 
            || poolTotalAmount <= 0) {
            pool.lastRewardBlock = block.number;
            return ;
        }

        uint256 poolReward = getBlocksReward(_pid, pool.lastRewardBlock, block.number);
        if (poolReward > 0) {
            if( address(pool.rewardToken) == address(booToken)) {
                booToken.mint(address(this), poolReward);
                booToken.mint(boodev, poolReward.div(8));   
            }
            pool.lastRewardClosed = pool.lastRewardClosed.add(poolReward);
            pool.accRewardPerShare = pool.accRewardPerShare.add(poolReward.mul(1e18).div(poolTotalAmount));
        }
        pool.lastRewardBlock = block.number;
    }

    function onAcionIn(uint256 _callId, address _account, uint256 _fromAmount, uint256 _toAmount) external override {
        if(!eventSources[msg.sender]) {
            return ;
        }
        for(uint256 u = 0; u < poolIndex[msg.sender][_callId].length; u ++) {
            uint256 pid = poolIndex[msg.sender][_callId][u];
            deposit(pid, _account, _fromAmount, _toAmount);
        }
    }

    function onAcionOut(uint256 _callId, address _account, uint256 _fromAmount, uint256 _toAmount) external override  {
        if(!eventSources[msg.sender]) {
            return ;
        }
        for(uint256 u = 0; u < poolIndex[msg.sender][_callId].length; u ++) {
            uint256 pid = poolIndex[msg.sender][_callId][u];
            withdraw(pid, _account, _fromAmount, _toAmount);
        }
    }

    function onAcionClaim(uint256 _callId, address _account) external override  {
        if(!eventSources[msg.sender]) {
            return ;
        }
        for(uint256 u = 0; u < poolIndex[msg.sender][_callId].length; u ++) {
            uint256 pid = poolIndex[msg.sender][_callId][u];
            if( !poolInfo[pid].autoClaim ) {
                continue;
            }
            _claim(pid, _account);
        }
    }

    function onAcionEmergency(uint256 _callId, address _account) external override  {
        _callId;
        _account;
    }

    function onAcionUpdate(uint256 _callId) external override  {
        if(!eventSources[msg.sender]) {
            return ;
        }
        for(uint256 u = 0; u < poolIndex[msg.sender][_callId].length; u ++) {
            uint256 pid = poolIndex[msg.sender][_callId][u];
            if( !poolInfo[pid].autoUpdate ) {
                continue;
            }
            updatePool(pid);
        }
    }

    function mintRewards(uint256 _pid) external override {
        updatePool(_pid);
        PoolInfo storage pool = poolInfo[_pid];
        address rewardToken = address(pool.rewardToken);
        if(rewardToken == address(booToken)) {
            return ;
        }
        uint256 balance = pool.rewardToken.balanceOf(address(this));
        if ( balance > tokenTotalRewards[rewardToken]) {
            uint256 mint = balance.sub(tokenTotalRewards[rewardToken]);
            pool.poolTotalRewards = pool.poolTotalRewards.add(mint);
            tokenTotalRewards[rewardToken] = balance;
        }
    }


    function deposit(uint256 _pid, address _account, uint256 _fromAmount, uint256 _toAmount) internal {
        updatePool(_pid);
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][_account];
        (,,uint256 poolTotalAmount) = IActionTrigger(pool.callFrom).getATPoolInfo(pool.callId);
        if (_fromAmount > 0) {
            uint256 totalAmountOld = safesub(poolTotalAmount, safesub(_toAmount, _fromAmount));
            user.rewardRemain = totalRewards(_pid, _account, _fromAmount, totalAmountOld)
                                    .add(user.rewardRemain)
                                    .sub(user.rewardDebt);
        }
        user.rewardDebt = totalRewards(_pid, _account, _toAmount, poolTotalAmount);
        emit ActionDeposit(_account, _pid, _fromAmount, _toAmount);
    }


    function withdraw(uint256 _pid, address _account, uint256 _fromAmount, uint256 _toAmount) internal {
        updatePool(_pid);
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][_account];
        (,,uint256 poolTotalAmount) = IActionTrigger(pool.callFrom).getATPoolInfo(pool.callId);
        if (_fromAmount > 0) {
            uint256 totalAmountOld = safesub(poolTotalAmount, safesub(_fromAmount, _toAmount));
            user.rewardRemain = totalRewards(_pid, _account, _fromAmount, totalAmountOld)
                                    .add(user.rewardRemain)
                                    .sub(user.rewardDebt);
        }
        user.rewardDebt = totalRewards(_pid, _account, _toAmount, poolTotalAmount);
        emit ActionWithdraw(_account, _pid, _fromAmount, _toAmount);
    }

    function claimAll() external returns (uint256 value) {
        uint256 length = poolInfo.length;
        for (uint256 pid = 0; pid < length; ++pid) {
            value = value.add(claim(pid));
        }

    }

    function claim(uint256 _pid) public returns (uint256 value) {
        return _claim(_pid, msg.sender);
    }

    function _claim(uint256 _pid, address _account) internal returns (uint256 value) {
        updatePool(_pid);
        PoolInfo storage pool = poolInfo[_pid];
        value = pendingRewards(_pid, _account);
        if (value > 0) {
            userInfo[_pid][_account].rewardRemain = 0;
            if(rewardRestricted[_account] > 0) {
                value = safesub(value, value.mul(rewardRestricted[_account]).div(1e9));
            }

            (,,uint256 poolTotalAmount) = IActionTrigger(pool.callFrom).getATPoolInfo(pool.callId);
            uint256 userAmount = IActionTrigger(pool.callFrom).getATUserAmount(pool.callId, _account);
            userInfo[_pid][_account].rewardDebt = totalRewards(_pid, _account, userAmount, poolTotalAmount);

            pool.lastRewardClosed = safesub(pool.lastRewardClosed, value);
            pool.poolTotalRewards = safesub(pool.poolTotalRewards, value);
            address rewardToken = address(pool.rewardToken);
            tokenTotalRewards[rewardToken] = safesub(tokenTotalRewards[rewardToken], value);

            value = safeTokenTransfer(pool.rewardToken, _account, value);
        }

        emit ActionClaim(_account, _pid, value);
    }


    function emergencyWithdraw(uint256 _pid, address _account) internal {
        _pid;
        _account;
    }


    function safesub(uint256 _a, uint256 _b) internal pure returns (uint256 v) {
        v = 0;
        if(_a > _b) {
            v = _a.sub(_b);
        }
    }


    function safeTokenTransfer(IERC20 _token, address _to, uint256 _amount) internal returns (uint256 value) {
        uint256 balance = _token.balanceOf(address(this));
        value = _amount > balance ? balance : _amount;
        if ( value > 0 ) {

            _token.transfer(_to, value);
        }
    }
}

pragma solidity ^0.5.0;

import "./aliana/GFAccessControl.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "./aliana/IAliana.sol";


contract AlianaMinting is GFAccessControl {
    using SafeMath for uint256;
    using SafeERC20 for IERC20;


    IERC20 public gftToken;
    IAliana public aliana;

    struct itmap {
        mapping(uint256 => IndexValue) data;
        KeyFlag[] keys;
        uint256 size;
    }
    struct IndexValue {
        uint256 keyIndex;
        uint256 value;
    }
    struct KeyFlag {
        uint256 key;
        bool deleted;
    }

    function insert(
        itmap storage self,
        uint256 key,
        uint256 value
    ) internal returns (bool replaced) {
        uint256 keyIndex = self.data[key].keyIndex;
        self.data[key].value = value;
        if (keyIndex > 0) return true;
        else {
            keyIndex = self.keys.length++;
            self.data[key].keyIndex = keyIndex + 1;
            self.keys[keyIndex].key = key;
            self.size++;
            return false;
        }
    }

    function remove(itmap storage self, uint256 key)
        internal
        returns (bool success)
    {
        uint256 keyIndex = self.data[key].keyIndex;
        if (keyIndex == 0) return false;
        delete self.data[key];
        self.keys[keyIndex - 1].deleted = true;
        self.size--;
        return true;
    }

    function contains(itmap storage self, uint256 key)
        internal
        view
        returns (bool)
    {
        return self.data[key].keyIndex > 0;
    }

    function iterate_start(itmap storage self)
        internal
        view
        returns (uint256 keyIndex)
    {
        return iterate_next(self, uint256(-1));
    }

    function iterate_valid(itmap storage self, uint256 keyIndex)
        internal
        view
        returns (bool)
    {
        return keyIndex < self.keys.length;
    }

    function iterate_next(itmap storage self, uint256 keyIndex)
        internal
        view
        returns (uint256 r_keyIndex)
    {
        keyIndex++;
        while (keyIndex < self.keys.length && self.keys[keyIndex].deleted)
            keyIndex++;
        return keyIndex;
    }

    function iterate_get(itmap storage self, uint256 keyIndex)
        internal
        view
        returns (uint256 key, uint256 value)
    {
        key = self.keys[keyIndex].key;
        value = self.data[key].value;
    }


    struct UserInfo {
        uint256 amount; 
        itmap amountToken;
        uint256 rewardDebt; 
        uint256 balance;











    }


    uint256 public accGFTPerShare;

    uint256 public lastRewardBlock;

    uint256 public rewardPerBlock;

    uint256 public labor;

    uint256 public rewardToDistribute;
    uint256 public maxMintingNumPerAddress = 9;


    mapping(address => UserInfo) userInfo;

    event RewardAdded(uint256 amount, bool isBlockReward);
    event Deposit(
        address indexed user,
        uint256 indexed tokenId,
        uint256 amount,
        uint256 pending
    );
    event Withdraw(
        address indexed user,
        uint256 indexed tokenId,
        uint256 amount,
        uint256 pending
    );
    event WithdrawPending(address indexed user, uint256 pending);
    event EmergencyWithdraw(address indexed user, uint256 amount);

    constructor(IERC20 _gftToken, IAliana _alianaAddr) public {
        require(_alianaAddr.isAliana(), "AlianaMinting: isAliana false");
        gftToken = _gftToken;
        aliana = _alianaAddr;
        lastRewardBlock = block.number;

        uint256 defaultPerDayIn5SecBlock = 2000;
        setRewardPerBlock(
            defaultPerDayIn5SecBlock.mul(1e18).div((24 * 60 * 60) / 5)
        );
    }

    function setMaxMintingNumPerAddress(uint256 _maxMintingNumPerAddress)
        public
        onlyCEO
    {
        maxMintingNumPerAddress = _maxMintingNumPerAddress;
    }

    function setRewardPerBlock(uint256 _rewardPerBlock) public onlyCEO {
        updateBlockReward();
        rewardPerBlock = _rewardPerBlock;
    }


    function pendingReward(address _user) external view returns (uint256) {
        UserInfo storage user = userInfo[_user];
        if (rewardPerBlock == 0) {
            return 0;
        }
        uint256 acps = accGFTPerShare;
        if (rewardPerBlock > 0) {
            uint256 lpSupply = labor;
            if (block.number > lastRewardBlock && lpSupply > 0) {
                acps = acps.add(rewardPending().mul(1e12).div(lpSupply));
            }
        }
        return user.amount.mul(acps).div(1e12).sub(user.rewardDebt);
    }

    function rewardPending() internal view returns (uint256) {
        uint256 reward = block.number.sub(lastRewardBlock).mul(rewardPerBlock);
        uint256 gaeBalance = gftToken.balanceOf(address(this)).sub(
            rewardToDistribute
        );
        if (gaeBalance < reward) {
            return gaeBalance;
        }
        return reward;
    }


    function updateBlockReward() public {
        if (block.number <= lastRewardBlock || rewardPerBlock == 0) {
            return;
        }
        uint256 lpSupply = labor;
        uint256 reward = rewardPending();
        if (lpSupply == 0 || reward == 0) {
            lastRewardBlock = block.number;
            return;
        }
        rewardToDistribute = rewardToDistribute.add(reward);
        emit RewardAdded(reward, true);
        lastRewardBlock = block.number;
        accGFTPerShare = accGFTPerShare.add(reward.mul(1e12).div(lpSupply));
    }

    function _depositFrom(address _from, uint256 _tokenId)
        internal
        whenNotPaused
    {
        require(
            aliana.ownerOf(_tokenId) == _from,
            "AlianaMinting: must be the owner"
        );
        UserInfo storage user = userInfo[_from];
        if (maxMintingNumPerAddress > 0) {
            require(
                user.amountToken.size < maxMintingNumPerAddress,
                "AlianaMinting: too much mining at the same time"
            );
        }
        (, , , , uint256 _amount) = aliana.getAliana(_tokenId);
        require(_amount > 0, "AlianaMinting: gene _amount must > 0");

        updateBlockReward();
        uint256 takePending;
        if (user.amount > 0) {
            uint256 pending = user.amount.mul(accGFTPerShare).div(1e12).sub(
                user.rewardDebt
            );
            if (pending > 0) {
                safeGFTTransfer(_from, pending);
            }
            takePending = pending;
        }

        aliana.transferFrom(address(_from), address(this), _tokenId);

        insert(user.amountToken, _tokenId, _amount);
        user.balance = user.balance.add(1);

        user.amount = user.amount.add(_amount);
        labor = labor.add(_amount);

        user.rewardDebt = user.amount.mul(accGFTPerShare).div(1e12);
        emit Deposit(_from, _tokenId, _amount, takePending);
    }


    function deposit(uint256 _tokenId) public whenNotPaused {
        _depositFrom(msg.sender, _tokenId);
    }


    function deposits(uint256[] memory _tokenIds) public whenNotPaused {
        for (uint256 i = 0; i < _tokenIds.length; i++) {
            deposit(_tokenIds[i]);
        }
    }


    function withdrawPending() public {
        UserInfo storage user = userInfo[msg.sender];
        updateBlockReward();
        uint256 pending = user.amount.mul(accGFTPerShare).div(1e12).sub(
            user.rewardDebt
        );
        if (pending > 0) {
            safeGFTTransfer(msg.sender, pending);
        }
        user.rewardDebt = user.amount.mul(accGFTPerShare).div(1e12);
        emit WithdrawPending(msg.sender, pending);
    }


    function withdraw(uint256 _tokenId) public {
        return _withdrawFrom(msg.sender, _tokenId);
    }

    function _withdrawFrom(address _from, uint256 _tokenId) internal {
        UserInfo storage user = userInfo[_from];
        uint256 _amount = user.amountToken.data[_tokenId].value;

        require(_amount > 0, "AlianaMinting: withdraw: not good 1");
        require(user.amount >= _amount, "AlianaMinting: withdraw: not good 2");

        updateBlockReward();
        uint256 pending = user.amount.mul(accGFTPerShare).div(1e12).sub(
            user.rewardDebt
        );
        if (pending > 0) {
            safeGFTTransfer(_from, pending);
        }

        require(
            remove(user.amountToken, _tokenId),
            "AlianaMinting: withdraw: not good, remove from amountToken"
        );
        user.balance = user.balance.sub(1);
        user.amount = user.amount.sub(_amount);
        aliana.safeTransferFrom(address(this), address(_from), _tokenId, "");

        user.rewardDebt = user.amount.mul(accGFTPerShare).div(1e12);
        labor = labor.sub(_amount);
        emit Withdraw(_from, _tokenId, _amount, pending);
    }


    function withdraws(uint256[] memory _tokenIds) public {
        for (uint256 i = 0; i < _tokenIds.length; i++) {
            withdraw(_tokenIds[i]);
        }
    }


    function withdrawsByCEO(address _from, uint256[] memory _tokenIds)
        public
        onlyCEO
    {
        for (uint256 i = 0; i < _tokenIds.length; i++) {
            _withdrawFrom(_from, _tokenIds[i]);
        }
    }


    function emergencyWithdraw() public {
        _emergencyWithdrawFrom(msg.sender);
    }


    function emergencyWithdrawByCEO(address _from) public onlyCEO {
        _emergencyWithdrawFrom(_from);
    }

    function _emergencyWithdrawFrom(address _from) internal {
        UserInfo storage user = userInfo[_from];
        uint256 amount = user.amount;

        for (
            uint256 i = iterate_start(user.amountToken);
            iterate_valid(user.amountToken, i);
            i = iterate_next(user.amountToken, i)
        ) {
            uint256 key = 0;
            uint256 value = 0;
            (key, value) = iterate_get(user.amountToken, i);
            aliana.safeTransferFrom(address(this), address(_from), key, "");
        }

        user.amount = 0;
        user.rewardDebt = 0;
        delete user.amountToken;
        user.balance = 0;
        labor = labor.sub(amount);
        emit EmergencyWithdraw(_from, amount);
    }


    function safeGFTTransfer(address _to, uint256 _amount) internal {
        uint256 gaeBalance = gftToken.balanceOf(address(this));
        require(gaeBalance >= _amount, "AlianaMinting: insufficient balance");
        rewardToDistribute = rewardToDistribute.sub(_amount);
        require(
            gftToken.transfer(_to, _amount),
            "AlianaMinting: failed to transfer gae token"
        );
    }

    function depositedTokens(address _owner)
        public
        view
        returns (uint256[] memory ownerTokens)
    {
        require(_owner != address(0), "AlianaMinting: zero address");

        UserInfo storage user = userInfo[_owner];
        uint256[] memory result = new uint256[](user.balance);
        uint256 resultIndex = 0;
        for (
            uint256 i = iterate_start(user.amountToken);
            iterate_valid(user.amountToken, i);
            i = iterate_next(user.amountToken, i)
        ) {
            uint256 key = 0;
            uint256 value = 0;
            (key, value) = iterate_get(user.amountToken, i);
            result[resultIndex] = key;
            resultIndex++;
        }
        return result;
    }


    function depositedBalanceOf(address _owner) public view returns (uint256) {
        require(_owner != address(0), "AlianaMinting: zero address");
        UserInfo storage user = userInfo[_owner];
        return user.balance;
    }

    function receiveApproval(
        address _sender,
        uint256 _value,
        address _tokenContract,
        bytes memory _extraData
    ) public {
        require(_value >= 0, "AlianaMinting: approval negative");
        uint256 action;
        assembly {
            action := mload(add(_extraData, 0x20))
        }
        require(action == 1, "AlianaMinting: unknow action");
        if (action == 1) {

            require(
                _tokenContract == address(aliana),
                "AlianaMinting: approval and want mint use aliana, but used token isn't Aliana"
            );
            uint256 tokenId;
            assembly {
                tokenId := mload(add(_extraData, 0x40))
            }
            _depositFrom(_sender, tokenId);
        }
    }
}

pragma solidity >=0.6.10 <=0.8.10;
pragma experimental ABIEncoderV2;

import {ERC20} from '@openzeppelin/contracts/token/ERC20/ERC20.sol';
import {IVault, IAsset, PoolSpecialization} from './interfaces/IVault.sol';
import {IPool} from './interfaces/IPool.sol';
import {ITranche} from './interfaces/ITranche.sol';
import {IDeploymentValidator} from './interfaces/IDeploymentValidator.sol';
import {IERC20Permit, IERC20} from '../../interfaces/IERC20Permit.sol';
import {IWrappedPosition} from './interfaces/IWrappedPosition.sol';
import {IRollupProcessor} from '../../interfaces/IRollupProcessor.sol';
import {MinHeap} from './MinHeap.sol';

import {IDefiBridge} from '../../interfaces/IDefiBridge.sol';

import {AztecTypes} from '../../aztec/AztecTypes.sol';



contract ElementBridge is IDefiBridge {
    using MinHeap for MinHeap.MinHeapData;


    error INVALID_TRANCHE();
    error INVALID_WRAPPED_POSITION();
    error INVALID_POOL();
    error INVALID_CALLER();
    error ASSET_IDS_NOT_EQUAL();
    error ASSET_NOT_ERC20();
    error INTERACTION_ALREADY_EXISTS();
    error POOL_NOT_FOUND();
    error UNKNOWN_NONCE();
    error BRIDGE_NOT_READY();
    error ALREADY_FINALISED();
    error TRANCHE_POSITION_MISMATCH();
    error TRANCHE_UNDERLYING_MISMATCH();
    error POOL_UNDERLYING_MISMATCH();
    error POOL_EXPIRY_MISMATCH();
    error TRANCHE_EXPIRY_MISMATCH();
    error VAULT_ADDRESS_VERIFICATION_FAILED();
    error VAULT_ADDRESS_MISMATCH();
    error TRANCHE_ALREADY_EXPIRED();
    error UNREGISTERED_POOL();
    error UNREGISTERED_POSITION();
    error UNREGISTERED_PAIR();



    struct Interaction {
        uint256 quantityPT;
        address trancheAddress;
        uint64 expiry;
        bool finalised;
        bool failed;
    }


    struct Pool {
        bytes32 poolId;
        address trancheAddress;
        address poolAddress;
        address wrappedPositionAddress;
    }

    enum TrancheRedemptionStatus { NOT_REDEEMED, REDEMPTION_FAILED, REDEMPTION_SUCCEEDED }


    struct TrancheAccount {
        uint256 quantityTokensHeld;
        uint256 quantityAssetRedeemed;
        uint256 quantityAssetRemaining;
        uint32 numDeposits;
        uint32 numFinalised;
        TrancheRedemptionStatus redemptionStatus;
    }


    address private immutable trancheFactory;


    bytes32 private immutable trancheBytecodeHash; 


    mapping(uint256 => Interaction) public interactions;


    mapping(address => uint64[]) public assetToExpirys;


    mapping(uint256 => Pool) public pools;


    mapping(address => TrancheAccount) private trancheAccounts;


    mapping (address => uint256) private trancheDeploymentBlockNumbers;


    address public immutable rollupProcessor;


    address private immutable balancerAddress;


    address private immutable elementDeploymentValidatorAddress;


    MinHeap.MinHeapData private heap;
    mapping(uint64 => uint256[]) private expiryToNonce;


    uint256 internal constant _FORTY_EIGHT_HOURS = 172800;

    uint256 internal constant MAX_INT = 2**256 - 1;

    uint256 internal constant MIN_GAS_FOR_CHECK_AND_FINALISE = 50000;
    uint256 internal constant MIN_GAS_FOR_FUNCTION_COMPLETION = 5000;
    uint256 internal constant MIN_GAS_FOR_FAILED_INTERACTION = 20000;
    uint256 internal constant MIN_GAS_FOR_EXPIRY_REMOVAL = 25000;


    event Convert(uint256 indexed nonce, uint256 totalInputValue);


    event Finalise(uint256 indexed nonce, bool success, string message);


    event PoolAdded(address poolAddress, address wrappedPositionAddress, uint64 expiry);


    constructor(
        address _rollupProcessor,
        address _trancheFactory,
        bytes32 _trancheBytecodeHash,
        address _balancerVaultAddress,
        address _elementDeploymentValidatorAddress
    ) {
        rollupProcessor = _rollupProcessor;
        trancheFactory = _trancheFactory;
        trancheBytecodeHash = _trancheBytecodeHash;
        balancerAddress = _balancerVaultAddress;
        elementDeploymentValidatorAddress = _elementDeploymentValidatorAddress;
        heap.initialise(100);
    }


    function getAssetExpiries(address asset) public view returns (uint64[] memory assetExpiries) {
        assetExpiries = assetToExpirys[asset];
    }





    function registerConvergentPoolAddress(
        address _convergentPool,
        address _wrappedPosition,
        uint64 _expiry
    ) external {
        checkAndStorePoolSpecification(_convergentPool, _wrappedPosition, _expiry);
    }






    function deriveTranche(address position, uint256 expiry) internal view virtual returns (address trancheContract) {
        bytes32 salt = keccak256(abi.encodePacked(position, expiry));
        bytes32 addressBytes = keccak256(abi.encodePacked(bytes1(0xff), trancheFactory, salt, trancheBytecodeHash));
        trancheContract = address(uint160(uint256(addressBytes)));
    }

    struct PoolSpec {
        uint256 poolExpiry;
        bytes32 poolId;
        address underlyingAsset;
        address trancheAddress;
        address tranchePosition;
        address trancheUnderlying;
        address poolUnderlying;
        address poolVaultAddress;
    }





    function checkAndStorePoolSpecification(
        address poolAddress,
        address wrappedPositionAddress,
        uint64 expiry        
    ) internal {
        PoolSpec memory poolSpec;
        IWrappedPosition wrappedPosition = IWrappedPosition(wrappedPositionAddress);

        try wrappedPosition.token() returns (IERC20 wrappedPositionToken) {
            poolSpec.underlyingAsset = address(wrappedPositionToken);
        } catch {
            revert INVALID_WRAPPED_POSITION();
        }

        poolSpec.trancheAddress = deriveTranche(wrappedPositionAddress, expiry);

        ITranche tranche = ITranche(poolSpec.trancheAddress);
        try tranche.position() returns (IERC20 tranchePositionToken) {
            poolSpec.tranchePosition = address(tranchePositionToken);
        } catch {
            revert INVALID_TRANCHE();
        }

        try tranche.underlying() returns (IERC20 trancheUnderlying) {
            poolSpec.trancheUnderlying = address(trancheUnderlying);
        } catch {
            revert INVALID_TRANCHE();
        }

        uint64 trancheExpiry = 0;
        try tranche.unlockTimestamp() returns (uint256 trancheUnlock) {
            trancheExpiry = uint64(trancheUnlock);
        } catch {
            revert INVALID_TRANCHE();
        }
        if (trancheExpiry != expiry) {
            revert TRANCHE_EXPIRY_MISMATCH();
        }

        if (poolSpec.tranchePosition != wrappedPositionAddress) {
            revert TRANCHE_POSITION_MISMATCH();
        }
        if (poolSpec.trancheUnderlying != poolSpec.underlyingAsset) {
            revert TRANCHE_UNDERLYING_MISMATCH();
        }

        IPool pool = IPool(poolAddress);
        try pool.underlying() returns (IERC20 poolUnderlying) {
            poolSpec.poolUnderlying = address(poolUnderlying);
        } catch {
            revert INVALID_POOL();
        }

        try pool.expiration() returns (uint256 poolExpiry) {
            poolSpec.poolExpiry = poolExpiry;
        } catch {
            revert INVALID_POOL();
        }

        try pool.getVault() returns (IVault poolVault) {
            poolSpec.poolVaultAddress = address(poolVault);
        } catch {
            revert INVALID_POOL();
        }

        try pool.getPoolId() returns (bytes32 poolId) {
            poolSpec.poolId = poolId;
        } catch {
            revert INVALID_POOL();
        }
        if (poolSpec.poolUnderlying != poolSpec.underlyingAsset) {
            revert POOL_UNDERLYING_MISMATCH();
        }
        if (poolSpec.poolExpiry != expiry) {
            revert POOL_EXPIRY_MISMATCH();
        }

        if (poolSpec.poolVaultAddress != balancerAddress) {
            revert VAULT_ADDRESS_VERIFICATION_FAILED();
        }



        IVault balancerVault = IVault(balancerAddress);
        (address balancersPoolAddress, ) = balancerVault.getPool(poolSpec.poolId);
        if (poolAddress != balancersPoolAddress) {
            revert VAULT_ADDRESS_MISMATCH();
        }


        validatePositionAndPoolAddresses(wrappedPositionAddress, poolAddress);


        uint256 assetExpiryHash = hashAssetAndExpiry(poolSpec.underlyingAsset, trancheExpiry);
        pools[assetExpiryHash] = Pool(poolSpec.poolId, poolSpec.trancheAddress, poolAddress, wrappedPositionAddress);
        uint64[] storage expiriesForAsset = assetToExpirys[poolSpec.underlyingAsset];
        uint256 expiryIndex = 0;
        while (expiryIndex < expiriesForAsset.length && expiriesForAsset[expiryIndex] != trancheExpiry) {
            ++expiryIndex;
        }
        if (expiryIndex == expiriesForAsset.length) {
            expiriesForAsset.push(trancheExpiry);
        }
        setTrancheDeploymentBlockNumber(poolSpec.trancheAddress);


        uint256[] storage nonces = expiryToNonce[trancheExpiry];
        if (nonces.length == 0) {
            expiryToNonce[trancheExpiry].push(MAX_INT);
        }
        emit PoolAdded(poolAddress, wrappedPositionAddress, trancheExpiry);
    }


    function setTrancheDeploymentBlockNumber(address trancheAddress) internal {
        uint256 trancheDeploymentBlock = trancheDeploymentBlockNumbers[trancheAddress];
        if (trancheDeploymentBlock == 0) {

            trancheDeploymentBlockNumbers[trancheAddress] = block.number;
        }
    }


    function getTrancheDeploymentBlockNumber(uint256 interactionNonce) public view returns (uint256 blockNumber) {
        Interaction storage interaction = interactions[interactionNonce];
        if (interaction.expiry == 0) {
            revert UNKNOWN_NONCE();
        }
        blockNumber = trancheDeploymentBlockNumbers[interaction.trancheAddress];
    }


    function validatePositionAndPoolAddresses(address wrappedPosition, address pool) internal {
        IDeploymentValidator validator = IDeploymentValidator(elementDeploymentValidatorAddress);
        if (!validator.checkPoolValidation(pool)) {
            revert UNREGISTERED_POOL();
        }
        if (!validator.checkWPValidation(wrappedPosition)) {
            revert UNREGISTERED_POSITION();
        }
        if (!validator.checkPairValidation(wrappedPosition, pool)) {
            revert UNREGISTERED_PAIR();
        }
    }





    function hashAssetAndExpiry(address asset, uint64 expiry) public pure returns (uint256 hashValue) {
        hashValue = uint256(keccak256(abi.encodePacked(asset, uint256(expiry))));
    }


    function convert(
        AztecTypes.AztecAsset calldata inputAssetA,
        AztecTypes.AztecAsset calldata,
        AztecTypes.AztecAsset calldata outputAssetA,
        AztecTypes.AztecAsset calldata,
        uint256 totalInputValue,
        uint256 interactionNonce,
        uint64 auxData,
        address
    )
        external
        payable
        override
        returns (
            uint256 outputValueA,
            uint256 outputValueB,
            bool isAsync
        )
    {

        if (msg.sender != rollupProcessor) {
            revert INVALID_CALLER();
        }
        if (inputAssetA.id != outputAssetA.id) {
            revert ASSET_IDS_NOT_EQUAL();
        }
        if (inputAssetA.assetType != AztecTypes.AztecAssetType.ERC20) {
            revert ASSET_NOT_ERC20();
        }
        if (interactions[interactionNonce].expiry != 0) {
            revert INTERACTION_ALREADY_EXISTS();
        }


        isAsync = true;
        outputValueA = 0;
        outputValueB = 0;

        Pool storage pool = pools[hashAssetAndExpiry(inputAssetA.erc20Address, auxData)];
        if (pool.trancheAddress == address(0)) {
            revert POOL_NOT_FOUND();
        }
        ITranche tranche = ITranche(pool.trancheAddress);
        if (block.timestamp >= tranche.unlockTimestamp()) {
            revert TRANCHE_ALREADY_EXPIRED();
        }
        uint64 trancheExpiry = uint64(tranche.unlockTimestamp());

        ERC20(inputAssetA.erc20Address).approve(balancerAddress, totalInputValue);

        address inputAsset = inputAssetA.erc20Address;

        uint256 principalTokensAmount = IVault(balancerAddress).swap(
            IVault.SingleSwap({
                poolId: pool.poolId,
                kind: IVault.SwapKind.GIVEN_IN,
                assetIn: IAsset(inputAsset),
                assetOut: IAsset(pool.trancheAddress),
                amount: totalInputValue,
                userData: '0x00'
            }),
            IVault.FundManagement({
                sender: address(this), 
                fromInternalBalance: false,
                recipient: payable(address(this)),
                toInternalBalance: false
            }),
            totalInputValue,
            block.timestamp
        );

        Interaction storage newInteraction = interactions[interactionNonce];
        newInteraction.expiry = trancheExpiry;
        newInteraction.failed = false;
        newInteraction.finalised = false;
        newInteraction.quantityPT = principalTokensAmount;
        newInteraction.trancheAddress = pool.trancheAddress;

        addNonceAndExpiry(interactionNonce, trancheExpiry);


        TrancheAccount storage trancheAccount = trancheAccounts[newInteraction.trancheAddress];
        trancheAccount.numDeposits++;
        trancheAccount.quantityTokensHeld += newInteraction.quantityPT;
        emit Convert(interactionNonce, totalInputValue);
        finaliseExpiredInteractions(MIN_GAS_FOR_FUNCTION_COMPLETION);       

    }


    function finaliseExpiredInteractions(uint256 gasFloor) internal {


        uint256 gasLoopCondition = MIN_GAS_FOR_CHECK_AND_FINALISE + MIN_GAS_FOR_FUNCTION_COMPLETION + gasFloor;
        uint256 ourGasFloor = MIN_GAS_FOR_FUNCTION_COMPLETION + gasFloor;
        while (gasleft() > gasLoopCondition) {


            (bool expiryAvailable, uint256 nonce) = checkNextExpiry(ourGasFloor);
            if (!expiryAvailable) {
                break;
            }

            uint256 gasRemaining = gasleft();
            if (gasRemaining <= ourGasFloor) {
                break;
            }
            uint256 gasForFinalise = gasRemaining - ourGasFloor;

            try IRollupProcessor(rollupProcessor).processAsyncDefiInteraction{gas: gasForFinalise}(nonce) returns (bool interactionCompleted) {

            } catch {
                break;
            }
        }
    }


    function finalise(
        AztecTypes.AztecAsset calldata,
        AztecTypes.AztecAsset calldata,
        AztecTypes.AztecAsset calldata outputAssetA,
        AztecTypes.AztecAsset calldata,
        uint256 interactionNonce,
        uint64
    )
        external
        payable
        override
        returns (
            uint256 outputValueA,
            uint256 outputValueB,
            bool interactionCompleted
        )
    {
        if (msg.sender != rollupProcessor) {
            revert INVALID_CALLER();
        }

        Interaction storage interaction = interactions[interactionNonce];
        if (interaction.expiry == 0) {
            revert UNKNOWN_NONCE();
        }
        if (interaction.expiry > block.timestamp) {
            revert BRIDGE_NOT_READY();
        }
        if (interaction.finalised) {
            revert ALREADY_FINALISED();
        }

        TrancheAccount storage trancheAccount = trancheAccounts[interaction.trancheAddress];
        if (trancheAccount.numDeposits == 0) {

            setInteractionAsFailure(interaction, interactionNonce, 'NO_DEPOSITS_FOR_TRANCHE');
            popInteraction(interaction, interactionNonce);
            return (0, 0, false);
        }


        if (trancheAccount.redemptionStatus != TrancheRedemptionStatus.REDEMPTION_SUCCEEDED) {


            ITranche tranche = ITranche(interaction.trancheAddress);
            try tranche.withdrawPrincipal(trancheAccount.quantityTokensHeld, address(this)) returns (uint256 valueRedeemed) {
                trancheAccount.quantityAssetRedeemed = valueRedeemed;
                trancheAccount.quantityAssetRemaining = valueRedeemed;
                trancheAccount.redemptionStatus = TrancheRedemptionStatus.REDEMPTION_SUCCEEDED;
            } catch Error(string memory errorMessage) {
                setInteractionAsFailure(interaction, interactionNonce, errorMessage);
                trancheAccount.redemptionStatus = TrancheRedemptionStatus.REDEMPTION_FAILED;
                popInteraction(interaction, interactionNonce);
                return (0, 0, false);
            } catch {
                setInteractionAsFailure(interaction, interactionNonce, 'UNKNOWN_ERROR_FROM_TRANCHE_WITHDRAW');
                trancheAccount.redemptionStatus = TrancheRedemptionStatus.REDEMPTION_FAILED;
                popInteraction(interaction, interactionNonce);
                return (0, 0, false);
            }
        }


        uint256 amountToAllocate = 0;
        if (trancheAccount.quantityTokensHeld == 0) {




            amountToAllocate = trancheAccount.quantityAssetRedeemed / trancheAccount.numDeposits;
        } else {

            amountToAllocate = (trancheAccount.quantityAssetRedeemed * interaction.quantityPT) / trancheAccount.quantityTokensHeld;
        }

        int256 numRemainingInteractionsForTranche = int256(uint256(trancheAccount.numDeposits)) - int256(uint256(trancheAccount.numFinalised));

        if (numRemainingInteractionsForTranche <= 1 || amountToAllocate > trancheAccount.quantityAssetRemaining) {


            amountToAllocate = trancheAccount.quantityAssetRemaining;
        }
        trancheAccount.quantityAssetRemaining -= amountToAllocate;
        trancheAccount.numFinalised++;


        ERC20(outputAssetA.erc20Address).approve(rollupProcessor, amountToAllocate);
        interaction.finalised = true;
        popInteraction(interaction, interactionNonce);
        outputValueA = amountToAllocate;
        outputValueB = 0;
        interactionCompleted = true;
        emit Finalise(interactionNonce, interactionCompleted, '');
    }


    function setInteractionAsFailure(
        Interaction storage interaction,
        uint256 interactionNonce,
        string memory message
    ) internal {
        interaction.failed = true;
        emit Finalise(interactionNonce, false, message);
    }


    function addNonceAndExpiry(uint256 nonce, uint64 expiry) internal returns (bool expiryAdded) {


        expiryAdded = false;
        uint256[] storage nonces = expiryToNonce[expiry];
        if (nonces.length == 1 && nonces[0] == MAX_INT) {
            nonces[0] = nonce;
        } else {
            nonces.push(nonce);
        }


        if (nonces.length == 1) {
            heap.add(expiry);
            expiryAdded = true;
        }
    }


    function popInteraction(Interaction storage interaction, uint256 interactionNonce) internal returns (bool expiryRemoved) {
        uint256[] storage nonces = expiryToNonce[interaction.expiry];
        if (nonces.length == 0) {
            return (false);
        }
        uint256 index = nonces.length - 1;
        while (index > 0 && nonces[index] != interactionNonce) {
            --index;
        }
        if (nonces[index] != interactionNonce) {
            return (false);
        }
        if (index != nonces.length - 1) {
            nonces[index] = nonces[nonces.length - 1];
        }
        nonces.pop();


        if (nonces.length == 0) {
            heap.remove(interaction.expiry);
            delete expiryToNonce[interaction.expiry];
            return (true);
        }
        return (false);
    }


    function checkNextExpiry(uint256 gasFloor)
        internal
        returns (
            bool expiryAvailable,
            uint256 nonce
        )
    {

        if (heap.size() == 0) {
            return (false, 0);
        }

        uint64 nextExpiry = heap.min();
        if (nextExpiry > block.timestamp) {

            return (false, 0);
        }

        uint256[] storage nonces = expiryToNonce[nextExpiry];
        uint256 minGasForLoop = (gasFloor + MIN_GAS_FOR_FAILED_INTERACTION);
        while (nonces.length > 0 && gasleft() >= minGasForLoop) {
            uint256 nextNonce = nonces[nonces.length - 1];
            if (nextNonce == MAX_INT) {


                nonces.pop();
                continue;
            }
            Interaction storage interaction = interactions[nextNonce];
            if (interaction.expiry == 0 || interaction.finalised || interaction.failed) {


                nonces.pop();
                continue;
            }

            (bool canBeFinalised, string memory message) = interactionCanBeFinalised(interaction);
            if (!canBeFinalised) {

                setInteractionAsFailure(interaction, nextNonce, message);
                nonces.pop();
                continue;
            }
            return (true, nextNonce);
        }


        if (nonces.length == 0 && gasleft() >= (gasFloor + MIN_GAS_FOR_EXPIRY_REMOVAL)) {

            heap.remove(nextExpiry);
        }
        return (false, 0);
    }


    function interactionCanBeFinalised(Interaction storage interaction) internal returns (bool canBeFinalised, string memory message) {
        TrancheAccount storage trancheAccount = trancheAccounts[interaction.trancheAddress];
        if (trancheAccount.numDeposits == 0) {

            return (false, 'NO_DEPOSITS_FOR_TRANCHE');
        }
        if (trancheAccount.redemptionStatus == TrancheRedemptionStatus.REDEMPTION_FAILED) {
            return (false, 'TRANCHE_REDEMPTION_FAILED');
        }

        if (trancheAccount.redemptionStatus == TrancheRedemptionStatus.REDEMPTION_SUCCEEDED) {

            if (trancheAccount.quantityAssetRemaining == 0) {

                return (false, 'ASSET_ALREADY_FULLY_ALLOCATED');
            }

            return (true, '');
        }

        ITranche tranche = ITranche(interaction.trancheAddress);
        uint256 speedbump = tranche.speedbump();
        if (speedbump != 0) {
            uint256 newExpiry = speedbump + _FORTY_EIGHT_HOURS;
            if (newExpiry > block.timestamp) {

                trancheAccount.redemptionStatus = TrancheRedemptionStatus.REDEMPTION_FAILED;
                return (false, 'SPEEDBUMP');
            }
        }
        address wpAddress = address(tranche.position());
        IWrappedPosition wrappedPosition = IWrappedPosition(wpAddress);
        address underlyingAddress = address(wrappedPosition.token());
        address yearnVaultAddress = address(wrappedPosition.vault());
        uint256 vaultQuantity = ERC20(underlyingAddress).balanceOf(yearnVaultAddress);
        if (trancheAccount.quantityTokensHeld > vaultQuantity) {
            trancheAccount.redemptionStatus = TrancheRedemptionStatus.REDEMPTION_FAILED;
            return (false, 'VAULT_BALANCE');
        }

        return (true, '');
    }
}

pragma solidity >=0.6.10 <=0.8.10;
